// ── AUTH ──────────────────────────────────────
// Split from the original single-file index.html module script — see
// CLAUDE.md for the module layout. Import wiring below was generated by
// AST-based free-variable analysis (eslint-scope), not manual tracing.
import { AppState } from './state.js';
import { init } from './app-init.js';
import { EmailAuthProvider, RecaptchaVerifier, auth, createUserWithEmailAndPassword, deleteDoc, deleteUser, getRedirectResult, googleProvider, linkWithPhoneNumber, onAuthStateChanged, reauthenticateWithCredential, reauthenticateWithPopup, sendPasswordResetEmail, signInWithEmailAndPassword, signInWithPhoneNumber, signInWithPopup, signInWithRedirect, signOut, unlink } from './core.js';
import { loadActiveProfileId, userDoc } from './firebase-sync.js';
import { closeManagers } from './settings-managers.js';
import { showToast, uiAlert, uiConfirm, uiPrompt } from './ui-widgets.js';

const setAuthMode = function(mode){
  AppState.authMode=mode;
  document.getElementById('auth-tab-login').classList.toggle('active',mode==='login');
  document.getElementById('auth-tab-register').classList.toggle('active',mode==='register');
  document.getElementById('auth-submit').textContent=mode==='login'?tr('auth_login_btn'):tr('auth_register_btn');
  document.getElementById('auth-password').setAttribute('autocomplete', mode==='login'?'current-password':'new-password');
  setAuthError('');
};

function setAuthError(msg){
  const el=document.getElementById('auth-error');
  if(el) el.textContent=msg||'';
}

function authErrorMessage(code,isPhoneFlow){
  const map={
    'auth/invalid-email':tr('auth_err_invalid_email'),
    'auth/user-not-found':tr('auth_err_user_not_found'),
    'auth/wrong-password':tr('auth_err_wrong_password'),
    'auth/invalid-credential':tr('auth_err_invalid_credential'),
    'auth/email-already-in-use':tr('auth_err_email_in_use'),
    'auth/weak-password':tr('auth_err_weak_password'),
    'auth/too-many-requests':tr('auth_err_too_many'),
    'auth/popup-closed-by-user':tr('auth_err_popup_closed'),
    'auth/invalid-phone-number':tr('auth_err_invalid_phone'),
    'auth/missing-phone-number':tr('auth_err_invalid_phone'),
    'auth/invalid-verification-code':tr('auth_err_invalid_code'),
    'auth/code-expired':tr('auth_err_code_expired'),
    'auth/quota-exceeded':tr('auth_err_quota'),
    'auth/operation-not-allowed':tr('auth_err_phone_disabled'),
    'auth/captcha-check-failed':tr('auth_err_captcha'),
    'auth/argument-error':tr('auth_err_captcha'),
    'auth/unauthorized-domain':tr('auth_err_unauthorized_domain'),
    'auth/network-request-failed':tr('auth_err_network'),
  };
  if(map[code]) return map[code];
  // Identity Toolkit sometimes fails a phone sendVerificationCode call with a
  // 503 wrapped as "auth/internal-error" or "auth/error-code:<n>" instead of
  // a normal auth/* code — seen for per-number SMS rate limits and
  // regional/carrier blocks on Google's side, not something a retry with the
  // same number fixes. Scoped to phone flows only: `auth/internal-error` can
  // also surface from email/Google sign-in for unrelated backend hiccups,
  // where the SMS-specific message would be misleading.
  if(isPhoneFlow && (code==='auth/internal-error' || /^auth\/error-code:/.test(code||''))) return tr('auth_err_sms_unavailable');
  return tr('auth_err_generic');
}

// TWA/APK installs (the app packaged for Google Play, see CLAUDE.md's
// "Android / Google Play packaging" section) and standalone-launched PWAs
// don't reliably support window.open()-based popups the way a normal
// browser tab does — confirmed by a real user report: Google sign-in
// failed with a generic error from both the installed TWA icon and the
// sideloaded APK, but worked fine from a plain browser tab/link. A TWA's
// document.referrer always starts with the android-app:// scheme (the
// standard, documented way to detect one); display-mode:standalone also
// catches an installed/Add-to-Home-Screen PWA, where popups are similarly
// unreliable. Redirect-based sign-in (full-page navigation instead of a
// second window) sidesteps the whole class of popup/COOP/third-party-
// cookie fragility, at the cost of a full navigation instead of an
// instant popup — an acceptable trade for these contexts, where popup
// sign-in doesn't just degrade, it silently fails outright.
function isPopupUnreliableContext(){
  try{
    if(document.referrer && document.referrer.startsWith('android-app://')) return true;
    if(window.matchMedia && window.matchMedia('(display-mode: standalone)').matches) return true;
  }catch(e){}
  return false;
}

// Marks that this session actually initiated a signInWithRedirect() round
// trip, so the getRedirectResult() check below (which runs unconditionally
// on every app load, not just after a real attempt) knows whether a
// failure is worth surfacing. Found the hard way on a real device: some
// TWA/WebView environments have getRedirectResult() reject with
// auth/internal-error on *every* load (likely an IndexedDB/persistence
// access restriction specific to that WebView, unrelated to any actual
// sign-in attempt) — without this guard, every user saw a scary "sign-in
// failed" banner the instant they opened the app, whether they'd ever
// touched the Google button or not.
const GOOGLE_REDIRECT_PENDING_KEY = 'zminkaGoogleRedirectPending';

const googleSignIn = async function(){
  setAuthError('');
  try{
    if(isPopupUnreliableContext()){
      try{ sessionStorage.setItem(GOOGLE_REDIRECT_PENDING_KEY, '1'); }catch(e){}
      await signInWithRedirect(auth, googleProvider);
    }
    else await signInWithPopup(auth, googleProvider);
  }
  catch(err){ console.error(err); setAuthError(authErrorMessage(err.code)); }
};

const resetPassword = async function(){
  const email=document.getElementById('auth-email').value.trim();
  if(!email){ setAuthError(tr('auth_enter_email')); return; }
  try{
    await sendPasswordResetEmail(auth,email);
    setAuthError(tr('auth_reset_sent'));
  }catch(err){
    console.error(err);
    setAuthError(authErrorMessage(err.code));
  }
};

const showPhoneAuth = function(){
  document.getElementById('auth-email-section').style.display='none';
  document.getElementById('auth-phone-section').style.display='block';
  setPhoneError('');
};

const hidePhoneAuth = function(){
  document.getElementById('auth-phone-section').style.display='none';
  document.getElementById('auth-email-section').style.display='';
  document.getElementById('auth-phone-code-group').style.display='none';
  document.getElementById('auth-phone-send-btn').style.display='';
  const codeInp=document.getElementById('auth-phone-code-input'); if(codeInp) codeInp.value='';
  AppState.phoneConfirmationResult=null;
  setPhoneError('');
};

function setPhoneError(msg){
  const el=document.getElementById('auth-phone-error');
  if(el) el.textContent=msg||'';
}

function resetRecaptchaContainer(containerId){
  const el=document.getElementById(containerId);
  if(el) el.innerHTML='';
}

function ensureRecaptcha(){
  if(!AppState.recaptchaVerifier) AppState.recaptchaVerifier=new RecaptchaVerifier(auth,'recaptcha-container',{size:'invisible'});
  return AppState.recaptchaVerifier;
}

const sendPhoneCode = async function(){
  const raw=document.getElementById('auth-phone-input').value.trim();
  if(!/^\+\d{8,15}$/.test(raw)){ setPhoneError(tr('auth_phone_bad_format')); return; }
  const btn=document.getElementById('auth-phone-send-btn');
  setPhoneError(''); btn.disabled=true;
  try{
    AppState.phoneConfirmationResult=await signInWithPhoneNumber(auth, raw, ensureRecaptcha());
    document.getElementById('auth-phone-code-group').style.display='block';
    btn.style.display='none';
    showToast(tr('auth_phone_code_sent'),'check');
  }catch(err){
    console.error(err);
    setPhoneError(authErrorMessage(err.code,true));
    if(AppState.recaptchaVerifier){ try{ AppState.recaptchaVerifier.clear(); }catch(e){} AppState.recaptchaVerifier=null; }
    // .clear() can itself throw mid-way (leaves the widget's DOM node behind),
    // so a retry's new RecaptchaVerifier fails with "already been rendered in
    // this element" — force the container empty regardless of .clear()'s outcome.
    resetRecaptchaContainer('recaptcha-container');
  }finally{
    btn.disabled=false;
  }
};

const verifyPhoneCode = async function(){
  const code=document.getElementById('auth-phone-code-input').value.trim();
  if(!code || !AppState.phoneConfirmationResult){ setPhoneError(tr('auth_phone_enter_code')); return; }
  const btn=document.getElementById('auth-phone-verify-btn');
  setPhoneError(''); btn.disabled=true;
  try{
    await AppState.phoneConfirmationResult.confirm(code);
    // onAuthStateChanged picks up the new session and hides the lock screen.
  }catch(err){
    console.error(err);
    setPhoneError(authErrorMessage(err.code,true));
  }finally{
    btn.disabled=false;
  }
};

const openLinkPhoneManager = function(){
  renderLinkPhoneUI();
  document.getElementById('link-phone-modal').style.display='flex';
};

export function renderLinkPhoneUI(){
  const phoneProvider=(AppState.currentUser?.providerData||[]).find(p=>p.providerId==='phone');
  const cur=document.getElementById('link-phone-current');
  const form=document.getElementById('link-phone-form');
  const sub=document.getElementById('settings-phone-sub');
  if(!cur||!form) return;
  if(phoneProvider){
    cur.style.display='block'; form.style.display='none';
    document.getElementById('link-phone-current-number').textContent=phoneProvider.phoneNumber;
    if(sub) sub.textContent=phoneProvider.phoneNumber;
  }else{
    cur.style.display='none'; form.style.display='block';
    if(sub) sub.textContent=tr('settings_phone_sub_empty');
  }
}

function ensureLinkRecaptcha(){
  if(!AppState.linkRecaptchaVerifier) AppState.linkRecaptchaVerifier=new RecaptchaVerifier(auth,'link-recaptcha-container',{size:'invisible'});
  return AppState.linkRecaptchaVerifier;
}

function setLinkPhoneError(msg){
  const el=document.getElementById('link-phone-error'); if(el) el.textContent=msg||'';
}

const sendLinkPhoneCode = async function(){
  const raw=document.getElementById('link-phone-input').value.trim();
  if(!/^\+\d{8,15}$/.test(raw)){ setLinkPhoneError(tr('auth_phone_bad_format')); return; }
  const btn=document.getElementById('link-phone-send-btn');
  setLinkPhoneError(''); btn.disabled=true;
  try{
    AppState.linkPhoneConfirmationResult=await linkWithPhoneNumber(AppState.currentUser, raw, ensureLinkRecaptcha());
    document.getElementById('link-phone-code-group').style.display='block';
    btn.style.display='none';
    showToast(tr('auth_phone_code_sent'),'check');
  }catch(err){
    console.error(err);
    setLinkPhoneError(authErrorMessage(err.code,true));
    if(AppState.linkRecaptchaVerifier){ try{ AppState.linkRecaptchaVerifier.clear(); }catch(e){} AppState.linkRecaptchaVerifier=null; }
    resetRecaptchaContainer('link-recaptcha-container');
  }finally{
    btn.disabled=false;
  }
};

const confirmLinkPhoneCode = async function(){
  const code=document.getElementById('link-phone-code-input').value.trim();
  if(!code || !AppState.linkPhoneConfirmationResult){ setLinkPhoneError(tr('auth_phone_enter_code')); return; }
  const btn=document.getElementById('link-phone-verify-btn');
  setLinkPhoneError(''); btn.disabled=true;
  try{
    await AppState.linkPhoneConfirmationResult.confirm(code);
    AppState.linkPhoneConfirmationResult=null;
    document.getElementById('link-phone-input').value='';
    document.getElementById('link-phone-code-input').value='';
    document.getElementById('link-phone-code-group').style.display='none';
    document.getElementById('link-phone-send-btn').style.display='';
    renderLinkPhoneUI();
    showToast(tr('settings_phone_linked'),'check');
  }catch(err){
    console.error(err);
    setLinkPhoneError(authErrorMessage(err.code,true));
  }finally{
    btn.disabled=false;
  }
};

const unlinkPhone = async function(){
  if(!(await uiConfirm(tr('settings_phone_remove_confirm'),{title:tr('settings_phone_remove_title'),okText:tr('common_delete'),danger:true}))) return;
  try{
    await unlink(AppState.currentUser,'phone');
    renderLinkPhoneUI();
    showToast(tr('settings_phone_removed'),'check');
  }catch(err){
    console.error(err);
    showToast(tr('settings_phone_remove_fail'),'xmark');
  }
};

const signOutUser = async function(){
  if(!(await uiConfirm(tr('auth_signout_confirm'),{title:tr('auth_signout_title'),okText:tr('auth_signout_ok')}))) return;
  await signOut(auth);
};

async function reauthenticateForDeletion(){
  const providerId=AppState.currentUser.providerData[0]?.providerId;
  try{
    if(providerId==='google.com'){
      await reauthenticateWithPopup(AppState.currentUser, googleProvider);
    }else{
      const password=await uiPrompt(tr('auth_reauth_prompt'),'',tr('auth_reauth_title'));
      if(!password) return false;
      await reauthenticateWithCredential(AppState.currentUser, EmailAuthProvider.credential(AppState.currentUser.email, password));
    }
    return true;
  }catch(e){
    console.error(e);
    return false;
  }
}

const deleteAccountUser = async function(){
  if(!AppState.currentUser) return;
  if(!(await uiConfirm(tr('auth_delete_confirm'),{title:tr('auth_delete_title'),okText:tr('common_delete'),danger:true}))) return;
  try{
    await Promise.all([
      deleteDoc(userDoc('shifts')),
      deleteDoc(userDoc('finance')),
      deleteDoc(userDoc('debt')),
    ]);
  }catch(e){
    console.error(e);
    await uiAlert(tr('auth_delete_data_fail'));
    return;
  }
  const uid=AppState.currentUser.uid;
  try{
    await deleteUser(AppState.currentUser);
  }catch(e){
    if(e.code==='auth/requires-recent-login' && await reauthenticateForDeletion()){
      try{
        await deleteUser(AppState.currentUser);
      }catch(e2){
        console.error(e2);
        await uiAlert(tr('auth_delete_account_fail'));
        return;
      }
    }else{
      console.error(e);
      await uiAlert(tr('auth_delete_needs_login'));
      return;
    }
  }
  ['shifts','tx','recurring','debt','cfg','pin','biocred'].forEach(n=>localStorage.removeItem(`mx_${n}_${uid}`));
  showToast(tr('auth_account_deleted'),'trash');
};

async function sha256Hex(str){
  const buf=await crypto.subtle.digest('SHA-256', new TextEncoder().encode(str));
  return Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,'0')).join('');
}

function pinKey(){ return AppState.currentUser ? `mx_pin_${AppState.currentUser.uid}` : null; }

function hasPinSet(){ const k=pinKey(); return !!(k && localStorage.getItem(k)); }

const ONBOARD_SLIDES=[
  {icon:'calendar', gradient:'linear-gradient(135deg,#8b5cf6,#a78bfa)', titleKey:'onboard_1_title', descKey:'onboard_1_desc'},
  {icon:'wallet', gradient:'linear-gradient(135deg,#10b981,#34d399)', titleKey:'onboard_2_title', descKey:'onboard_2_desc'},
  {icon:'swap', gradient:'linear-gradient(135deg,#0ea5e9,#22d3ee)', titleKey:'onboard_3_title', descKey:'onboard_3_desc'},
  {icon:'bank', gradient:'linear-gradient(135deg,#f59e0b,#fb923c)', titleKey:'onboard_4_title', descKey:'onboard_4_desc'},
  {icon:'lock', gradient:'linear-gradient(135deg,#8b5cf6,#ec4899)', titleKey:'onboard_5_title', descKey:'onboard_5_desc'},
];

function onboardKey(){ return AppState.currentUser ? `mx_onboarded_${AppState.currentUser.uid}` : null; }

function renderOnboardSlide(){
  const s=ONBOARD_SLIDES[AppState.onboardIndex];
  const icon=document.getElementById('onboard-icon');
  if(icon){ icon.style.background=s.gradient; icon.innerHTML=window.Icon(s.icon); }
  const title=document.getElementById('onboard-title'); if(title) title.textContent=tr(s.titleKey);
  const desc=document.getElementById('onboard-desc'); if(desc) desc.textContent=tr(s.descKey);
  const dots=document.getElementById('onboard-dots');
  if(dots) dots.innerHTML=ONBOARD_SLIDES.map((_,i)=>`<div class="onboard-dot${i===AppState.onboardIndex?' active':''}"></div>`).join('');
  const next=document.getElementById('onboard-next-btn');
  if(next) next.textContent = AppState.onboardIndex===ONBOARD_SLIDES.length-1 ? tr('onboard_start') : tr('onboard_next');
}

const onboardNext = function(){
  if(AppState.onboardIndex<ONBOARD_SLIDES.length-1){ AppState.onboardIndex++; renderOnboardSlide(); }
  else finishOnboarding();
};

const finishOnboarding = function(){
  const k=onboardKey(); if(k) localStorage.setItem(k,'1');
  const scr=document.getElementById('onboard-screen');
  if(scr){ scr.classList.add('lock-hide'); setTimeout(()=>{scr.style.display='none'; scr.classList.remove('lock-hide');},320); }
};

function maybeShowOnboarding(){
  const k=onboardKey();
  if(!k || localStorage.getItem(k)) return;
  AppState.onboardIndex=0;
  renderOnboardSlide();
  const scr=document.getElementById('onboard-screen');
  if(scr){ scr.style.display='flex'; scr.classList.remove('lock-hide'); }
}

function settingsTipKey(){ return AppState.currentUser ? `mx_tip_settings_search_${AppState.currentUser.uid}` : null; }

const dismissSettingsTip = function(){
  const k=settingsTipKey(); if(k) localStorage.setItem(k,'1');
  const el=document.getElementById('settings-contextual-tip'); if(el) el.style.display='none';
};

export function maybeShowSettingsTip(){
  const k=settingsTipKey();
  const el=document.getElementById('settings-contextual-tip'); if(!el) return;
  el.style.display = (k && !localStorage.getItem(k)) ? 'flex' : 'none';
}

async function checkPinLock(){
  if(!hasPinSet()){ AppState.pinUnlocked=true; return; }
  if(AppState.pinUnlocked) return;
  const scr=document.getElementById('pin-screen');
  const err=document.getElementById('pin-unlock-error');
  if(err) err.textContent='';
  if(scr){ scr.style.display='flex'; scr.classList.remove('lock-hide'); }
  const bioBtn=document.getElementById('pin-bio-unlock-btn');
  if(bioBtn) bioBtn.style.display = hasBioSet() ? '' : 'none';
  const inp=document.getElementById('pin-unlock-input');
  if(inp){ inp.value=''; setTimeout(()=>inp.focus(),150); }
}

const tryUnlockPin = async function(){
  const inp=document.getElementById('pin-unlock-input');
  const err=document.getElementById('pin-unlock-error');
  const val=(inp&&inp.value||'').trim();
  if(!val){ if(err) err.textContent=tr('pin_enter'); return; }
  const hash=await sha256Hex(val);
  const k=pinKey();
  if(k && localStorage.getItem(k)===hash){
    AppState.pinUnlocked=true;
    if(err) err.textContent='';
    const scr=document.getElementById('pin-screen');
    if(scr){ scr.classList.add('lock-hide'); setTimeout(()=>{scr.style.display='none'; scr.classList.remove('lock-hide'); maybeShowOnboarding();},320); }
  }else{
    if(err) err.textContent=tr('pin_wrong');
    if(inp){ inp.value=''; inp.focus(); }
  }
};

const forgotPin = async function(){
  if(!(await uiConfirm(tr('pin_forgot_confirm'),{title:tr('pin_forgot_title'),okText:tr('pin_forgot_ok'),danger:true}))) return;
  const k=pinKey(); if(k) localStorage.removeItem(k);
  const bk=bioKey(); if(bk) localStorage.removeItem(bk);
  AppState.pinUnlocked=true; // avoid a re-lock flash while the sign-out transition runs
  await signOut(auth);
};

const openPinSettings = async function(){
  const statusEl=document.getElementById('pin-status-text');
  const removeBtn=document.getElementById('pin-remove-btn');
  const lockBtn=document.getElementById('pin-lock-now-btn');
  const set=hasPinSet();
  if(statusEl) statusEl.textContent = set ? tr('pin_status_set') : tr('pin_status_unset');
  if(removeBtn) removeBtn.style.display = set ? '' : 'none';
  if(lockBtn) lockBtn.style.display = set ? '' : 'none';
  const ni=document.getElementById('pin-new-input'); if(ni) ni.value='';
  const ci=document.getElementById('pin-confirm-input'); if(ci) ci.value='';
  document.getElementById('pin-settings-modal').style.display='flex';
  await renderBioSettingsUI();
};

const setPin = async function(){
  const ni=document.getElementById('pin-new-input');
  const ci=document.getElementById('pin-confirm-input');
  const v1=(ni&&ni.value||'').trim(), v2=(ci&&ci.value||'').trim();
  if(!/^\d{4,6}$/.test(v1)){ showToast(tr('pin_len_error'),'xmark'); return; }
  if(v1!==v2){ showToast(tr('pin_mismatch'),'xmark'); return; }
  const hash=await sha256Hex(v1);
  const k=pinKey(); if(!k) return;
  localStorage.setItem(k, hash);
  AppState.pinUnlocked=true;
  closeManagers();
  showToast(tr('pin_set_success'),'check');
};

const removePin = function(){
  const k=pinKey(); if(k) localStorage.removeItem(k);
  const bk=bioKey(); if(bk) localStorage.removeItem(bk); // biometric requires a PIN fallback to exist
  closeManagers();
  showToast(tr('pin_removed'),'check');
};

const lockNow = function(){
  if(!hasPinSet()){ showToast(tr('pin_set_first'),'xmark'); return; }
  closeManagers();
  AppState.pinUnlocked=false;
  checkPinLock();
};

function bioSupported(){ return !!(window.PublicKeyCredential && navigator.credentials); }

async function bioPlatformAvailable(){
  if(!bioSupported()) return false;
  try{ return await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable(); }
  catch(e){ return false; }
}

function bioKey(){ return AppState.currentUser ? `mx_biocred_${AppState.currentUser.uid}` : null; }

function hasBioSet(){ const k=bioKey(); return !!(k && localStorage.getItem(k)); }

function randBytes(len){ const a=new Uint8Array(len); crypto.getRandomValues(a); return a; }

function b64FromBuf(buf){ return btoa(String.fromCharCode(...new Uint8Array(buf))); }

function bufFromB64(b64){ return Uint8Array.from(atob(b64), c=>c.charCodeAt(0)); }

async function renderBioSettingsUI(){
  const wrap=document.getElementById('pin-bio-section');
  if(!wrap) return;
  const enableBtn=document.getElementById('pin-bio-enable-btn');
  const disableBtn=document.getElementById('pin-bio-disable-btn');
  const available = hasPinSet() && await bioPlatformAvailable();
  if(!available){ wrap.style.display='none'; return; }
  wrap.style.display='block';
  const on=hasBioSet();
  if(enableBtn) enableBtn.style.display = on?'none':'';
  if(disableBtn) disableBtn.style.display = on?'':'none';
}

const enableBiometric = async function(){
  if(!hasPinSet()){ showToast(tr('pin_set_first'),'xmark'); return; }
  try{
    const cred=await navigator.credentials.create({
      publicKey:{
        challenge: randBytes(32),
        rp:{ name:'Zminka' },
        user:{ id: randBytes(16), name: (AppState.currentUser&&AppState.currentUser.email)||'user', displayName:'Zminka' },
        pubKeyCredParams:[{type:'public-key',alg:-7},{type:'public-key',alg:-257}],
        authenticatorSelection:{ authenticatorAttachment:'platform', userVerification:'required' },
        timeout:60000,
      }
    });
    if(!cred) throw new Error('no credential returned');
    const k=bioKey(); if(k) localStorage.setItem(k, b64FromBuf(cred.rawId));
    await renderBioSettingsUI();
    showToast(tr('pin_bio_on'),'check');
  }catch(e){
    console.error(e);
    showToast(tr('pin_bio_fail'),'xmark');
  }
};

const disableBiometric = async function(){
  const k=bioKey(); if(k) localStorage.removeItem(k);
  await renderBioSettingsUI();
  showToast(tr('pin_bio_off'),'check');
};

const tryBioUnlock = async function(){
  const k=bioKey(); const credB64=k&&localStorage.getItem(k);
  if(!credB64) return;
  try{
    const assertion=await navigator.credentials.get({
      publicKey:{
        challenge: randBytes(32),
        allowCredentials:[{ id: bufFromB64(credB64), type:'public-key' }],
        userVerification:'required',
        timeout:60000,
      }
    });
    if(!assertion) return;
    AppState.pinUnlocked=true;
    const err=document.getElementById('pin-unlock-error'); if(err) err.textContent='';
    const scr=document.getElementById('pin-screen');
    if(scr){ scr.classList.add('lock-hide'); setTimeout(()=>{scr.style.display='none'; scr.classList.remove('lock-hide'); maybeShowOnboarding();},320); }
  }catch(e){
    console.error(e);
    // Cancelled or failed — the PIN field is still right there, no need to surface an error.
  }
};

// Top-level statements that DO something immediately (as opposed to a
// plain declaration) - deferred into this function and called from
// app.js only after every module in the import graph has finished
// evaluating, so nothing here can hit a temporal-dead-zone reference to
// another chunk's not-yet-initialized export (this is exactly the class
// of bug that broke 'auth' being read before core.js's declaration of it
// had run, when this was still ordinary top-level code in this file).
export function __init_auth__(){
// Phase 5 of the window.*/inline-onclick removal audit item (see CLAUDE.md):
// this file has no dynamic per-row templates of its own (unlike the earlier
// phases) — all 25 window.* exports below existed purely so a static
// onclick="fn()" attribute in index.html could resolve `fn` as a global.
// Replaced with a data-action attribute dispatched through one capture-phase
// click listener (same CLICK_ACTIONS pattern as phases 3-4; capture matters
// here too since several of these buttons sit inside a .modal-card with its
// own onclick="event.stopPropagation()", e.g. the PIN settings and
// link-phone modals).
const CLICK_ACTIONS = {
  'set-auth-mode': ds=>setAuthMode(ds.mode),
  'google-sign-in': ()=>googleSignIn(),
  'reset-password': ()=>resetPassword(),
  'show-phone-auth': ()=>showPhoneAuth(),
  'hide-phone-auth': ()=>hidePhoneAuth(),
  'send-phone-code': ()=>sendPhoneCode(),
  'verify-phone-code': ()=>verifyPhoneCode(),
  'open-link-phone-manager': ()=>openLinkPhoneManager(),
  'send-link-phone-code': ()=>sendLinkPhoneCode(),
  'confirm-link-phone-code': ()=>confirmLinkPhoneCode(),
  'unlink-phone': ()=>unlinkPhone(),
  'sign-out-user': ()=>signOutUser(),
  'delete-account-user': ()=>deleteAccountUser(),
  'onboard-next': ()=>onboardNext(),
  'finish-onboarding': ()=>finishOnboarding(),
  'dismiss-settings-tip': ()=>dismissSettingsTip(),
  'try-unlock-pin': ()=>tryUnlockPin(),
  'forgot-pin': ()=>forgotPin(),
  'open-pin-settings': ()=>openPinSettings(),
  'set-pin': ()=>setPin(),
  'remove-pin': ()=>removePin(),
  'lock-now': ()=>lockNow(),
  'enable-biometric': ()=>enableBiometric(),
  'disable-biometric': ()=>disableBiometric(),
  'try-bio-unlock': ()=>tryBioUnlock(),
};
document.addEventListener('click', e=>{
  const el=e.target.closest('[data-action]');
  if(el && CLICK_ACTIONS[el.dataset.action]) CLICK_ACTIONS[el.dataset.action](el.dataset);
}, true);

// Completes a signInWithRedirect() flow (see googleSignIn/isPopupUnreliableContext
// above) after the full-page navigation back from Google. onAuthStateChanged
// below already reacts to the resulting sign-in on success, so this only
// needs to surface an error — a redirect-flow failure otherwise has no
// synchronous try/catch to report through, unlike the popup path. Only
// shown to the user if GOOGLE_REDIRECT_PENDING_KEY confirms a redirect was
// actually attempted this session — see that constant's comment above for
// why an unconditional getRedirectResult() call can reject on every load
// in some environments regardless of whether sign-in was ever attempted.
getRedirectResult(auth).catch(err=>{
  console.error(err);
  let wasPending=false;
  try{ wasPending = sessionStorage.getItem(GOOGLE_REDIRECT_PENDING_KEY)==='1'; }catch(e){}
  if(wasPending) setAuthError(authErrorMessage(err.code));
}).finally(()=>{
  try{ sessionStorage.removeItem(GOOGLE_REDIRECT_PENDING_KEY); }catch(e){}
});

// Still window-exposed: tests/smoke.mjs, tests/e2e-crud.mjs, and
// tests/e2e-modals.mjs all call window.finishOnboarding() directly to
// dismiss the onboarding overlay, rather than clicking the button.
window.finishOnboarding = finishOnboarding;
document.getElementById('auth-form').addEventListener('submit', async function(e){
  e.preventDefault();
  const email=document.getElementById('auth-email').value.trim();
  const password=document.getElementById('auth-password').value;
  const btn=document.getElementById('auth-submit');
  setAuthError(''); btn.disabled=true;
  try{
    if(AppState.authMode==='login') await signInWithEmailAndPassword(auth,email,password);
    else await createUserWithEmailAndPassword(auth,email,password);
  }catch(err){
    console.error(err);
    setAuthError(authErrorMessage(err.code));
  }finally{
    btn.disabled=false;
  }
});
(function bindPinEnter(){
  const inp=document.getElementById('pin-unlock-input');
  if(inp) inp.addEventListener('keydown', e=>{ if(e.key==='Enter'){ e.preventDefault(); tryUnlockPin(); } });
})();
onAuthStateChanged(auth, async (user)=>{
  AppState.currentUser=user;
  if(user) loadActiveProfileId();
  const lockScreen=document.getElementById('lock-screen');
  const signOutBtn=document.getElementById('settings-signout');
  const deleteBtn=document.getElementById('settings-delete-account');
  const pinBtn=document.getElementById('settings-pin');
  if(user){
    if(lockScreen){ lockScreen.classList.add('lock-hide'); setTimeout(()=>{lockScreen.style.display='none';},320); }
    if(signOutBtn) signOutBtn.style.display='';
    if(deleteBtn) deleteBtn.style.display='';
    if(pinBtn) pinBtn.style.display='';
    await init();
    await checkPinLock();
    if(!hasPinSet()) maybeShowOnboarding();
  }else{
    AppState.shifts={}; AppState.transactions=[]; AppState.recurring=[]; AppState.shoppingList=[]; AppState.debts=[]; AppState.currentDebtId=null;
    AppState.activeProfileId='default'; AppState.profilesMeta={list:[{id:'default', name:''}], updatedAt:0};
    AppState.pinUnlocked=false;
    if(signOutBtn) signOutBtn.style.display='none';
    if(deleteBtn) deleteBtn.style.display='none';
    if(pinBtn) pinBtn.style.display='none';
    const pinScreen=document.getElementById('pin-screen');
    if(pinScreen) pinScreen.style.display='none';
    if(lockScreen){ lockScreen.style.display='flex'; lockScreen.classList.remove('lock-hide'); }
    const form=document.getElementById('auth-form'); if(form) form.reset();
    setAuthError('');
    if(document.getElementById('auth-phone-section')?.style.display!=='none') hidePhoneAuth();
  }
});
}
